INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('13-growth-engine',2,13,'GROWTH ENGINE','Mo hinh tang truong Growth Engine',13,'draft','2026-06-20T11:50:28Z','2026-06-20T11:50:28Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('eb392db3-afd9-4d79-a94b-fef909029f41','13-growth-engine',NULL,2,'13.1 Growth Engine là gì và cách nó vận hành ra sao?','131-growth-engine-la-gi-va-cach-no-van-hanh-ra-sao',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cdad0d6d-88f6-4268-a242-571f1b532bad','eb392db3-afd9-4d79-a94b-fef909029f41',0,'image',NULL,'book/13-growth-engine/2d5a3440-a22e-4dd6-9678-18e59bd826c3-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bcdc15ae-a703-403e-ae15-9a47caf59040','eb392db3-afd9-4d79-a94b-fef909029f41',1,'text','Trong quá trình vận hành và chuẩn hóa hệ thống cho phòng khám RHM, tôi nhận ra một sai lầm phổ biến: chúng ta thường nhầm lẫn giữa Marketing và Growth Engine (Cỗ máy tăng trưởng).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ab47038-4711-44a0-82d4-396e054067d5','eb392db3-afd9-4d79-a94b-fef909029f41',2,'text','Nhiều người đổ rất nhiều tiền vào quảng cáo, hy vọng mang lại khách hàng. Nhưng nếu thiếu đi một hệ thống kết nối chặt chẽ phía sau, tiền marketing sẽ giống như muối bỏ bể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fe13feb3-be7a-4e2e-a464-1ed1a027e9d9','eb392db3-afd9-4d79-a94b-fef909029f41',3,'text','Hãy nhìn nhận một cách có hệ thống thế này: Nếu **Personal Brand** (Thương hiệu cá nhân) là thỏi nam châm tạo niềm tin, **Media Network** (Mạng lưới truyền thông) là cánh tay nối dài tạo độ phủ, và **Clinic System** (Hệ thống phòng khám) là nền tảng cốt lõi để tạo ra trải nghiệm điều trị xuất sắc; thì **Growth Engine** chính là hệ thống chuyển hóa tất cả những giá trị vô hình đó thành kết quả hữu hình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ba747a20-450a-42e8-93a4-a72fa2a82987','eb392db3-afd9-4d79-a94b-fef909029f41',4,'text','Đó là một cỗ máy tinh vi nhằm biến đổi xuyên suốt hành trình của một bệnh nhân theo công thức:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e098cc4e-8fec-4ece-9960-9760db9365d5','eb392db3-afd9-4d79-a94b-fef909029f41',5,'text','**Nội dung → Lead → Tư vấn → Đặt lịch → Điều trị → Review → Giới thiệu → Doanh thu**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5421bed4-dfa2-4471-97d7-502e387bea01','eb392db3-afd9-4d79-a94b-fef909029f41',6,'image',NULL,'book/13-growth-engine/97254990-32bd-40ba-a1fb-94c179ac2647-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39349cd4-9396-4341-9048-43e46a170f31','eb392db3-afd9-4d79-a94b-fef909029f41',7,'text','Growth Engine không chỉ đơn thuần là marketing. Nó là bộ não trung tâm, nơi truyền thông, quảng cáo, dữ liệu, kịch bản bán hàng, quy trình chăm sóc và sự tự động hóa hòa quyện vào nhau thành một dòng chảy không đứt đoạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8afb381d-f51f-4661-a792-80cff85e1ca2','eb392db3-afd9-4d79-a94b-fef909029f41',8,'text','Để hiểu rõ cách cỗ máy này vận hành, chúng ta sẽ bóc tách nó thành 3 bánh răng chính:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57c9d52e-cd14-4cc3-a0cd-7b9a02617af5','eb392db3-afd9-4d79-a94b-fef909029f41',9,'text','**Bánh răng thứ nhất: Lực hút và Chuyển đổi (Từ Nội dung đến Đặt lịch)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b770573c-5c43-416d-81dd-5fdf469d49e4','eb392db3-afd9-4d79-a94b-fef909029f41',10,'text','Mọi thứ bắt đầu từ một điểm chạm nội dung. Một video ngắn truyền tải tinh thần "thích làm răng", một bài viết kiến thức, hay một chiến dịch ưu đãi không chỉ để đếm lượt xem (views) hay lượt thích (likes). Nhiệm vụ của nó là phải thu về **Lead** (khách hàng tiềm năng).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4d0e0cd-0180-4dec-bf1b-0321457b7fee','eb392db3-afd9-4d79-a94b-fef909029f41',11,'text','Nhưng có Lead rồi thì sao? Cỗ máy tăng trưởng đòi hỏi một quy trình xử lý dữ liệu lập tức. Từ lúc số điện thoại đổ về hệ thống CRM cho đến khi đội ngũ Telesale gọi điện tư vấn, khoảng thời gian đó càng ngắn, tỷ lệ chuyển đổi thành **Đặt lịch** càng cao. Ở giai đoạn này, tốc độ và sự thấu hiểu nỗi đau của khách hàng (muốn niềng răng, bọc sứ hay làm implant) là yếu tố quyết định.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65ab98af-88ec-4ccd-ac54-c21156042cdf','eb392db3-afd9-4d79-a94b-fef909029f41',12,'text','**Bánh răng thứ hai: Trải nghiệm lâm sàng (Từ Điều trị đến Review)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4418146b-d4d9-41ff-a463-d0d08966d04b','eb392db3-afd9-4d79-a94b-fef909029f41',13,'text','Khách hàng bước qua cánh cửa phòng khám là lúc **Clinic System** tiếp quản, nhưng Growth Engine vẫn âm thầm hoạt động. Mọi checklist hàng ngày, từ cách lễ tân chào đón, sự chuẩn bị kỹ lưỡng của trợ thủ, đến tay nghề và sự tận tâm của bác sĩ đều đóng góp vào trải nghiệm **Điều trị**. Và đây là điểm mấu chốt mà nhiều phòng khám bỏ lỡ: Đừng để khách hàng ra về trong im lặng. Một trải nghiệm xuất sắc phải được đóng gói thành **Review**. Cỗ máy tăng trưởng cần những quy trình khéo léo để khuyến khích bệnh nhân để lại đánh giá 5 sao trên Google Maps hoặc quay những video chia sẻ cảm nhận ngay tại ghế răng khi họ đang hài lòng nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1869ddd5-3b6b-43c8-864e-94f8e169bd2f','eb392db3-afd9-4d79-a94b-fef909029f41',14,'text','**Bánh răng thứ ba: Vòng lặp Lan tỏa (Từ Giới thiệu đến Doanh thu)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f37e01e1-27e9-4bc8-9866-dd44b707fb14','eb392db3-afd9-4d79-a94b-fef909029f41',15,'text','Đây là tầng tạo ra lợi nhuận bền vững nhất cho phòng khám. Một Growth Engine khỏe mạnh là khi nó tự sinh ra khách hàng mới mà không tốn thêm chi phí quảng cáo (CAC = 0). Từ sự hài lòng tuyệt đối, cộng với một chương trình chăm sóc sau điều trị (Post-care) tự động và tinh tế, bệnh nhân cũ sẽ trở thành những đại sứ thương hiệu. Họ bắt đầu **Giới thiệu** người thân, bạn bè. Vòng lặp chính thức khép kín và mở ra một chu kỳ mới, đẩy **Doanh thu** tăng trưởng đều đặn và có thể dự báo trước.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dda3c7a8-ec5c-4e77-9a20-ad8a0c240c2b','eb392db3-afd9-4d79-a94b-fef909029f41',16,'text','**Tóm lại:** Xây dựng Growth Engine là việc bạn gắn kết các hòn đảo rời rạc trong phòng khám lại với nhau. Nội dung của đội Media phải khớp với kịch bản của đội Sales. Lời hứa của Sales phải được đội ngũ Bác sĩ thực hiện hoàn hảo tại phòng khám. Và sự tận tâm của Bác sĩ phải được đội Chăm sóc khách hàng chuyển hóa thành những lời giới thiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04ab1c33-6425-499a-97fd-a964892b80bb','eb392db3-afd9-4d79-a94b-fef909029f41',17,'text','Khi tất cả các bánh răng này vận hành đồng bộ và trơn tru, bạn không chỉ đang điều hành một phòng khám nha khoa, mà bạn đang sở hữu một cỗ máy in tiền tự động và bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fc2734c0-f7dd-4c22-9360-6e48f1097d17','13-growth-engine',NULL,2,'13.2 Content, Ads, CRM, Sales, Data, Automation','132-content-ads-crm-sales-data-automation',1,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3dbe40d3-3f1b-4955-bd9e-9097eaea0289','13-growth-engine','fc2734c0-f7dd-4c22-9360-6e48f1097d17',3,'Content chuyển đổi - Nhiên liệu cho cổ máy tăng trưởng','content-chuyen-oi-nhien-lieu-cho-co-may-tang-truong',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('42df3c08-e262-444e-9b1c-4ef7cce502b1','3dbe40d3-3f1b-4955-bd9e-9097eaea0289',18,'text','Nếu Growth Engine là một cỗ máy hoàn hảo, thì Content (Nội dung) chính là dòng nhiên liệu đầu tiên để kích hoạt toàn bộ hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e28393dc-2455-4a75-b43e-8de21a0a743c','3dbe40d3-3f1b-4955-bd9e-9097eaea0289',19,'text','Trong quá trình điều hành và tối ưu hóa phòng khám RHM, tôi thường nói với đội ngũ của mình rằng: Nội dung không đơn thuần là những bài viết hay video đăng lên mạng xã hội cho có tụ. Mỗi một nội dung được tạo ra phải là một "nhân viên sale" mẫn cán, làm việc 24/7 để thay đổi tâm lý bệnh nhân, giúp họ từ e ngại chuyển sang mong muốn làm, và cuối cùng là tự nguyện bước đến phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('777a348c-0d74-41cf-834d-3991cfa2d39c','13-growth-engine','3dbe40d3-3f1b-4955-bd9e-9097eaea0289',4,'Để làm được điều đó, chúng ta cần nhìn nhận hệ thống nội dung qua 5 vai trò chiến lược:','e-lam-uoc-ieu-o-chung-ta-can-nhin-nhan-he-thong-noi-dung-qua-5-vai-tro-chien-luo',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ecf107b8-7116-44bc-bc6b-fccdca0441c1','777a348c-0d74-41cf-834d-3991cfa2d39c',20,'text','- **Tạo nhận diện:** Là điểm chạm đầu tiên để khách hàng biết đến bác sĩ và định vị của phòng khám giữa hàng ngàn lựa chọn khác.- **Xây dựng niềm tin:** Giải mã những thuật ngữ y khoa phức tạp thành ngôn ngữ bình dân, dễ hiểu. Niềm tin bắt nguồn từ sự thấu hiểu.- **Khơi gợi nhu cầu:** Rất nhiều người không biết mình đang gặp vấn đề cho đến khi xem một nội dung chỉ đúng tình trạng của họ.- **Tạo Lead (Chuyển đổi):** Nhiệm vụ sinh tử của nội dung là khiến khách hàng phải hành động—inbox, bình luận, gọi điện thoại hoặc trực tiếp điền form đặt lịch.- **Tích lũy tài sản dài hạn:** Một video trên TikTok, một bài viết chuyên sâu trên Website, hay một kho dữ liệu Review không biến mất sau khi chiến dịch kết thúc. Chúng tích lũy theo thời gian và trở thành tài sản số vô giá của thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a46b1e53-f63a-43ad-a2b8-b4a29a54b2c0','13-growth-engine','3dbe40d3-3f1b-4955-bd9e-9097eaea0289',4,'Bức tranh đa diện: các nhóm content cốt lõi','buc-tranh-a-dien-cac-nhom-content-cot-loi',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c8112a75-a7c7-4d98-acdb-33cd9e7da089','a46b1e53-f63a-43ad-a2b8-b4a29a54b2c0',21,'image',NULL,'book/13-growth-engine/86b39fef-7638-420e-a1f4-15dfef780efc-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('570a271e-422b-4a69-a3e4-0a7db5fe288a','a46b1e53-f63a-43ad-a2b8-b4a29a54b2c0',22,'text','Để không bị cạn kiệt ý tưởng và đảm bảo tiếp cận đa chiều, nội dung của phòng khám cần được phân bổ đều vào các nhóm sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0f4174f3-93d0-4f34-8730-9f619e0fe54d','a46b1e53-f63a-43ad-a2b8-b4a29a54b2c0',23,'text','- **Giáo dục (Education):** Cung cấp kiến thức, giải thích cặn kẽ các vấn đề nha khoa. Đây là nền tảng để thể hiện sự chuyên nghiệp.- **Case Study thực tế:** Không gì thuyết phục hơn những ca lâm sàng thành công. Đây là cách chứng minh năng lực điều trị rõ ràng nhất.- **Review bệnh nhân:** Tiếng nói của khách hàng cũ chính là bằng chứng xã hội (Social Proof) mạnh mẽ nhất để phá vỡ sự hoài nghi của khách hàng mới.- **Hậu trường (Behind the scenes):** Những thước phim chân thực về hoạt động diễn ra tại phòng khám, quy trình vô trùng vô khuẩn, hay sự cẩn thận của trợ thủ... tạo ra sự gần gũi và an tâm tuyệt đối.- **Thương hiệu Bác sĩ/Người sáng lập:** Xây dựng hình ảnh chuyên gia, định hình phong cách và triết lý điều trị riêng biệt.- **So sánh Trước - Sau (Before/After):** Đánh thẳng vào thị giác, tạo ra sự khao khát được thay đổi nụ cười và sự tự tin.- **Giải đáp hiểu lầm:** Xóa bỏ các rào cản tâm lý (sợ đau, sợ đắt, sợ mài răng hỏng...).- **Livestream / Q&A:** Tương tác thời gian thực để giải đáp thắc mắc, kéo gần khoảng cách giữa bác sĩ và bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ff7f7ceb-46f4-45bf-9237-655f0bed07b4','13-growth-engine','3dbe40d3-3f1b-4955-bd9e-9097eaea0289',4,'Công thức cho content nha khoa','cong-thuc-cho-content-nha-khoa',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e08c8f0c-e1b9-4fd9-8677-474e0aa4110d','ff7f7ceb-46f4-45bf-9237-655f0bed07b4',24,'text','Sáng tạo là vô hạn, nhưng để nội dung thực sự tạo ra dòng tiền, nó phải tuân thủ một công thức mang tính quy luật. Một content tạo chuyển đổi cao luôn là sự kết hợp của 4 yếu tố:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a8411b9e-d0a0-4ada-aa91-71ec7f85f0e5','ff7f7ceb-46f4-45bf-9237-655f0bed07b4',25,'text','**[Nỗi đau của bệnh nhân] + [Góc nhìn chuyên môn] + [Bằng chứng thật] + [Lời kêu gọi hành động rõ ràng] = Nội dung tạo chuyển đổi (Lead)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0f4e254c-482c-4420-bc14-a490ab92abc7','ff7f7ceb-46f4-45bf-9237-655f0bed07b4',26,'image',NULL,'book/13-growth-engine/a22ea2de-305b-4d1e-aa49-ad4be78d75c0-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b5207860-9445-411e-8994-f5d4d1ccb4be','ff7f7ceb-46f4-45bf-9237-655f0bed07b4',27,'text','Thay vì thao thao bất tuyệt về máy móc hiện đại, hãy bắt đầu bằng sự đồng cảm với nỗi đau của họ, đưa ra giải pháp dưới góc nhìn của một chuyên gia, chứng minh bằng những ca đã thành công, và cuối cùng, chỉ cho họ biết bước tiếp theo họ cần làm là gì (ví dụ: "Nhấn vào link để đặt lịch khám miễn phí").',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('640642ff-38de-45b7-a145-7a0baf44842a','ff7f7ceb-46f4-45bf-9237-655f0bed07b4',28,'text','**Ví dụ ứng dụng thực chiến vào từng dịch vụ:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a34e20f4-c63a-4d32-9a6c-707367aae5b0','ff7f7ceb-46f4-45bf-9237-655f0bed07b4',29,'text','- **Niềng răng:** Thay vì nói "Phòng khám chúng tôi niềng răng rẻ nhất", hãy làm chủ đề: *"3 sai lầm tai hại khiến bạn niềng răng nhiều năm nhưng vẫn hỏng".*- **Implant:** *"Tại sao mất răng lâu năm lại dẫn đến hóp má, tiêu xương và giải pháp cứu vãn".*- **Răng sứ Veneer:** Không phải ai cũng làm được Veneer. Chủ đề *"Ai tuyệt đối KHÔNG NÊN dán sứ Veneer?"* sẽ tạo ra sự tin tưởng tuyệt đối nhờ tính trung thực.- **Tẩy trắng răng:** Đánh thẳng vào nỗi lo sợ: *"Tẩy trắng răng có làm hỏng men răng và gây ê buốt như lời đồn?"*- **Điều trị tủy:** *"Đau nhức răng kéo dài về đêm: Cảnh báo nguy hiểm bạn không thể phớt lờ".*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0e68507c-eaba-429b-adc1-44d574b06649','ff7f7ceb-46f4-45bf-9237-655f0bed07b4',30,'text','Một khi bạn chuẩn hóa được hệ thống nội dung này, Growth Engine của phòng khám sẽ luôn được tiếp nhiên liệu dồi dào, mở đường cho một dòng chảy khách hàng liên tục và chất lượng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('06380570-6722-4a46-9017-52c5365e39c0','13-growth-engine','fc2734c0-f7dd-4c22-9360-6e48f1097d17',3,'ADS - Khuếch đại và tối ưu hành trình niềm tin','ads-khuech-ai-va-toi-uu-hanh-trinh-niem-tin',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86fa9fd8-321e-4994-9992-076d5fa0767b','06380570-6722-4a46-9017-52c5365e39c0',31,'text','Nếu Content (Nội dung) là khối tài sản cốt lõi cần thời gian để tích lũy, thì Ads (Quảng cáo) chính là chân ga giúp cỗ máy Growth Engine bứt tốc, mang thương hiệu tiếp cận thị trường mục tiêu trong thời gian ngắn nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cacdd9fb-2a3f-4099-ac51-150f77b85e92','06380570-6722-4a46-9017-52c5365e39c0',32,'text','Tuy nhiên, trong quá trình đo lường hiệu suất và tối ưu hóa chi phí cho hệ thống phòng khám RHM, tôi nhận thấy một chiếc bẫy cực kỳ nguy hiểm mà rất nhiều chủ phòng khám mắc phải: **Đồng nhất việc chạy quảng cáo với việc chạy khuyến mãi.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('74af61c0-b133-45c4-b3f5-ae21956d72f3','06380570-6722-4a46-9017-52c5365e39c0',33,'text','Nhiều người mang tư duy "đốt tiền" để lấy số lượng. Họ liên tục tung ra các gói giảm giá sốc, niềng răng giá rẻ, bọc sứ tặng kèm... Kết quả của sai lầm này là một vòng luẩn quẩn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('846462cb-c371-4605-b90d-d1aa5d5cb43c','06380570-6722-4a46-9017-52c5365e39c0',34,'text','**Chạy giảm giá → Bão Lead (rất rẻ nhưng kém chất lượng) → Đội ngũ tư vấn mệt mỏi, khó chốt → Lợi nhuận mỏng, thậm chí lỗ.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('12c1fdbb-aaa4-4c91-9d5a-ab8c38aa1a8f','06380570-6722-4a46-9017-52c5365e39c0',35,'text','Cách làm đúng đắn và bền vững của một Growth Engine là sử dụng Ads để **dẫn dắt hành trình niềm tin**. Khách hàng cần trải qua một quá trình từ việc nhận thức vấn đề, tin tưởng chuyên môn của bác sĩ, cho đến khi họ thực sự có cảm hứng, *thích làm răng* và tự nguyện quyết định điều trị. Khi đó, Lead trả về sẽ vô cùng chất lượng, tỷ lệ đặt lịch cao và giá trị vòng đời khách hàng (LTV) hoàn toàn xứng đáng với chi phí bỏ ra.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('872d187b-050b-4ed4-918f-7ec21822f858','06380570-6722-4a46-9017-52c5365e39c0',36,'text','Để làm được điều này, hệ thống quảng cáo không thể chỉ có một chiến dịch duy nhất, mà phải được chia thành các tầng (Layers) phối hợp nhịp nhàng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d793a1e6-00f5-413d-a652-acce62f7f20e','13-growth-engine','06380570-6722-4a46-9017-52c5365e39c0',4,'6 Tầng Quảng Cáo Trọng Điểm Của Phòng Khám Nha Khoa','6-tang-quang-cao-trong-iem-cua-phong-kham-nha-khoa',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('50cc16be-4dcb-4de6-8389-03dda7b4dee0','d793a1e6-00f5-413d-a652-acce62f7f20e',37,'image',NULL,'book/13-growth-engine/35a127d0-339f-4411-b33d-067b6c7b7170-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92e9d764-983f-45b0-bfef-1fec66bb0149','d793a1e6-00f5-413d-a652-acce62f7f20e',38,'text','- **Awareness Ads (Tầng Nhận diện):** Mục tiêu là phủ sóng hình ảnh chuyên gia của bác sĩ và cơ sở vật chất của phòng khám. Ở tầng này, chúng ta không bán hàng, chúng ta đang "gieo hạt" vào tâm trí khách hàng.- **Trust Ads (Tầng Niềm tin):** Khuếch đại các video giáo dục kiến thức, phô diễn các ca lâm sàng (Case study) thành công và review chân thực. Đây là lúc khách hàng bắt đầu thấy bạn là một chuyên gia đáng tin cậy.- **Lead Ads (Tầng Thu thập):** Bắt đầu tung ra các chiến dịch yêu cầu hành động rõ ràng để thu thập số điện thoại, form đăng ký, hoặc tin nhắn inbox.- **Remarketing Ads (Tầng Bám đuổi):** "Tái tiếp thị" những người đã xem video giáo dục hơn 15 giây, những người đã vào website tìm hiểu giá nhưng chưa quyết định, hoặc những người đã inbox nhưng bỗng dưng im lặng. Đừng để họ rơi rớt khỏi phễu.- **Conversion Ads (Tầng Chuyển đổi):** Tung ra các cú hích quyết định (như ưu đãi thăm khám 1:1 với bác sĩ trưởng, voucher tặng máy tăm nước khi chốt lịch) để thúc đẩy họ nhấc máy gọi điện hoặc đến trực tiếp phòng khám.- **Retention Ads (Tầng Giữ chân):** Chạy quảng cáo hiển thị riêng cho tệp khách hàng cũ, nhắc nhở họ lịch tái khám, lấy cao răng định kỳ hoặc giới thiệu các dịch vụ gia tăng khác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('48a82df6-bb1d-4581-acbd-f2e0b5c87c00','13-growth-engine','06380570-6722-4a46-9017-52c5365e39c0',4,'Phễu Ads Chuẩn Mực Cho Ngành Nha Khoa','pheu-ads-chuan-muc-cho-nganh-nha-khoa',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6721f75b-3c43-467d-bbae-d285fce315f7','48a82df6-bb1d-4581-acbd-f2e0b5c87c00',39,'text','Sự kết hợp của 6 tầng trên tạo ra một phễu lọc hoàn hảo. Bạn có thể hình dung kịch bản dòng chảy của khách hàng như sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fbe745e1-64fe-4a72-b5c2-5cd873e9d37b','48a82df6-bb1d-4581-acbd-f2e0b5c87c00',40,'image',NULL,'book/13-growth-engine/560e71e7-8596-4af6-ae98-aa77de2df072-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7c363980-c1fe-4ed3-b03d-8ef49c614f15','13-growth-engine','06380570-6722-4a46-9017-52c5365e39c0',4,'Quản Trị Bằng Con Số: Bộ KPI Sinh Tử Của Hệ Thống Ads','quan-tri-bang-con-so-bo-kpi-sinh-tu-cua-he-thong-ads',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('78db1d99-f466-4920-8294-db0ef05d9b0d','7c363980-c1fe-4ed3-b03d-8ef49c614f15',41,'image',NULL,'book/13-growth-engine/74ccbe66-89a3-4453-94e5-8edac3ab5412-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('893feb72-815b-4435-9a0c-dc3a9682b477','7c363980-c1fe-4ed3-b03d-8ef49c614f15',42,'text','Chạy quảng cáo mà không đo lường chi tiết thì chẳng khác nào ném tiền qua cửa sổ. Để làm chủ chân ga này, người vận hành phải nằm lòng các chỉ số KPI sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1051fd8b-5c9f-46b4-b00a-a73b586b4013','7c363980-c1fe-4ed3-b03d-8ef49c614f15',43,'text','- **CPM (Chi phí tiếp cận):** Cho biết bạn đang phải trả bao nhiêu tiền để nội dung hiển thị trước 1.000 người.- **CTR (Tỷ lệ click):** Phản ánh mức độ hấp dẫn của hình ảnh, tiêu đề và thông điệp. Nếu CTR thấp, nội dung của bạn đang quá nhàm chán hoặc tiếp cận sai tệp.- **CPC (Chi phí trên mỗi lượt click) & CPL (Chi phí tạo 1 Lead):** Đo lường giá thành của từng tin nhắn hoặc số điện thoại thu về.- **Booking Rate (Tỷ lệ Lead đặt lịch):** Thước đo đánh giá chất lượng của Lead và kỹ năng kịch bản của đội Telesale.- **Show-up Rate (Tỷ lệ khách đến khám):** Lead chốt lịch rồi có đến đúng hẹn hay không? Chỉ số này đánh giá hiệu quả của hệ thống nhắc lịch tự động.- **CAC (Chi phí thu mua một khách hàng mới):** Con số quan trọng bậc nhất. Tổng tiền quảng cáo chia cho số lượng khách hàng thực tế mở hồ sơ điều trị.- **ROAS (Lợi nhuận trên chi phí quảng cáo):** Bỏ ra 1 đồng quảng cáo, phòng khám thu về bao nhiêu đồng doanh thu? Đây là câu trả lời cuối cùng cho sự thành bại của chiến dịch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('80736eaf-b9a7-40cf-b7a7-8bbcf1282234','7c363980-c1fe-4ed3-b03d-8ef49c614f15',44,'text','Quảng cáo không phải là phép thuật, nó là toán học kết hợp với tâm lý học. Khi bạn thiết lập một hệ thống Ads bài bản, đồng bộ hóa nó với kho Content chất lượng và hệ thống CRM chặt chẽ, bạn sẽ kiểm soát hoàn toàn đầu vào của cỗ máy tăng trưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f70e5e40-3bed-4201-ae03-93c3525e750f','13-growth-engine','fc2734c0-f7dd-4c22-9360-6e48f1097d17',3,'CRM - "Bộ nhớ trung tâm" trong chăm sóc khách hàng','crm-bo-nho-trung-tam-trong-cham-soc-khach-hang',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f43ba8a3-ed69-494b-8905-2d3fd5aab1c5','f70e5e40-3bed-4201-ae03-93c3525e750f',45,'text','Trong hành trình xây dựng và chuẩn hóa quy trình cho phòng khám, tôi từng chứng kiến một kịch bản rất quen thuộc và cũng vô cùng lãng phí: Bỏ ra hàng chục triệu chạy quảng cáo, nội dung thu hút được vô số sự quan tâm, nhưng cuối cùng tỷ lệ chốt vẫn lẹt đẹt. Tại sao?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a0fd4da3-12f0-43f5-9b6c-44e97a580f45','f70e5e40-3bed-4201-ae03-93c3525e750f',46,'text','Bởi vì phòng khám thiếu đi một hệ thống CRM (Customer Relationship Management). Nếu Content là nhiên liệu, Ads là chân ga, thì CRM chính là "bộ nhớ trung tâm" nơi lưu trữ, phân loại và xử lý mọi cơ hội tạo ra doanh thu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8751b5a7-bfbf-4e53-b8ba-cef3e7ecf359','f70e5e40-3bed-4201-ae03-93c3525e750f',47,'text','Khi không có CRM, chúng ta sẽ phải đối mặt với những kẽ hở chết người trong vận hành:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65c43777-fb58-465c-96a6-881fc1476af3','f70e5e40-3bed-4201-ae03-93c3525e750f',48,'text','- **Inbox rải rác đa kênh:** Bệnh nhân nhắn tin từ Facebook, Zalo, TikTok, Website nhưng không được quy về một mối, dẫn đến việc không biết khách đến từ nguồn nào để đánh giá hiệu quả.- **Không phân loại Lead:** Mọi khách hàng đều được tư vấn bằng một kịch bản như nhau, không trúng "nỗi đau" (niềng răng khác với implant hay bọc sứ), dẫn đến tỷ lệ chốt thấp.- **Bỏ quên khâu Follow-up (Chăm sóc lại):** Khách hàng chưa sẵn sàng chốt ngay, nhân viên quên gọi lại, thế là chúng ta mất khách vào tay đối thủ.- **Mất dấu lịch sử trao đổi:** Mỗi lần khách hàng liên hệ lại là một lần nhân viên phải hỏi lại từ đầu: *"Dạ anh/chị tên gì, anh/chị muốn tư vấn gì ạ?"* – Trải nghiệm này giết chết sự chuyên nghiệp.- **Mù mờ về dữ liệu:** Cuối tháng, quản lý không thể biết được kênh nào mang lại khách hàng thực tế, nhân sự nào chốt sale tốt nhất, dẫn đến việc ra quyết định dựa trên cảm tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ddc9cec5-e7cc-4c21-a663-c7c69bbe4478','f70e5e40-3bed-4201-ae03-93c3525e750f',49,'text','Để biến triết lý làm cho khách hàng thực sự "thích làm răng" thành hiện thực, mọi điểm chạm cần phải mượt mà. Khách hàng phải cảm thấy họ được thấu hiểu ngay từ tin nhắn đầu tiên. Và đó là lúc CRM phát huy sức mạnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('37d9da2a-6a8c-4608-81f1-df6fc3395010','13-growth-engine','f70e5e40-3bed-4201-ae03-93c3525e750f',4,'Một hệ thống CRM chuẩn thường cần quản lý các nhóm dữ liệu gì?','mot-he-thong-crm-chuan-thuong-can-quan-ly-cac-nhom-du-lieu-gi',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('477d5c69-db29-4588-9a11-7b9487a16ba0','37d9da2a-6a8c-4608-81f1-df6fc3395010',50,'text','Không cần quá phức tạp, nhưng một CRM hiệu quả cho nha khoa phải bao quát được bức tranh toàn cảnh của từng bệnh nhân thông qua các nhóm dữ liệu cốt lõi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e1f5e1ba-90ae-46af-9ef3-a288baaba4ea','37d9da2a-6a8c-4608-81f1-df6fc3395010',51,'text','- **Hồ sơ khách hàng định danh:** Tên, Số điện thoại, Zalo, và Nguồn đến (Ads Facebook, Search Google, TikTok hay Giới thiệu).- **Nhu cầu cốt lõi:** Họ đang quan tâm đến dịch vụ gì? (Niềng răng, Implant, Veneer, Tẩy trắng hay Khám tổng quát).- **Trạng thái Lead:** Khách mới vào, đang tư vấn, đã đặt lịch, hay đã đến khám?- **Mức độ tiềm năng (Nhiệt độ khách hàng):** Đánh giá mức độ Nóng (Sẵn sàng chốt ngay), Ấm (Đang cân nhắc), hay Lạnh (Chỉ hỏi giá).- **Phân quyền phụ trách:** Gắn tên nhân sự chịu trách nhiệm (Telesale, Tư vấn viên trực tiếp, Nhân viên CSKH).- **Quản trị Lịch hẹn:** Ngày giờ, bác sĩ tiếp nhận và dịch vụ thực hiện.- **Lịch sử tương tác:** Ghi chú lại toàn bộ nội dung đã trao đổi, những băn khoăn của khách để người sau tiếp quản có thể nắm bắt ngay lập tức.- **Theo dõi Doanh thu:** Tổng giá trị gói điều trị, số tiền đã cọc, số tiền đã thanh toán và công nợ.- **Lịch Follow-up:** Cài đặt ngày giờ cần gọi lại và nội dung cụ thể cần nhắc nhở khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b433552c-37cd-4e12-846c-10624326a7e5','13-growth-engine','f70e5e40-3bed-4201-ae03-93c3525e750f',4,'Bản đồ hành trình: pipeline &amp; trạng thái lead trong crm','ban-o-hanh-trinh-pipeline-amp-trang-thai-lead-trong-crm',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('abdbf636-df7e-4ece-8ab0-e3509bd8df9b','b433552c-37cd-4e12-846c-10624326a7e5',52,'text','Sức mạnh thực sự của CRM nằm ở **Pipeline** – đường ống dẫn dắt khách hàng qua từng giai đoạn của Growth Engine. Một đường ống chuẩn mực trong nha khoa sẽ trải qua các điểm chạm sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f810d4fe-a39d-4f66-8cf3-2d9f3738bc89','b433552c-37cd-4e12-846c-10624326a7e5',53,'text','**Lead mới** → **Đã liên hệ** → **Đã tư vấn** → **Đã đặt lịch** → **Đã đến khám** → **Đã chốt điều trị** → **Đang điều trị** → **Hoàn tất** → **Review** → **Referral (Giới thiệu)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('20096dec-401b-4462-865f-1231df2bf7db','b433552c-37cd-4e12-846c-10624326a7e5',54,'text','Mỗi bệnh nhân rơi vào đường ống này sẽ được gắn với một **Trạng thái (Status)** cụ thể. Quản lý các trạng thái này giúp đội ngũ biết chính xác mình cần làm gì tiếp theo:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da0d1cd2-5e7f-45ae-b9a1-e14d00817326','b433552c-37cd-4e12-846c-10624326a7e5',55,'text','- **New Lead (Lead mới):** Khách vừa để lại thông tin. Bắt buộc phải có Telesale bốc máy gọi ngay trong vòng 5-10 phút.- **Contacted (Đã liên hệ):** Đã kết nối được với khách nhưng chưa thể tư vấn sâu.- **Qualified (Đạt chuẩn):** Xác định được khách có nhu cầu thực tế và nằm trong tệp khách hàng mục tiêu của phòng khám (có khả năng chi trả).- **Booked (Đã đặt lịch):** Khách đã hẹn ngày giờ qua phòng khám. Giai đoạn này cần hệ thống SMS/Zalo nhắc lịch tự động.- **No-show (Không đến hẹn):** Khách bùng lịch. Đội CSKH cần có kịch bản gọi lại để tìm hiểu lý do và đặt lịch hẹn lại.- **Consulted (Đã được tư vấn trực tiếp):** Khách đã đến khám và nghe bác sĩ lên phác đồ điều trị.- **Treatment Accepted (Đồng ý điều trị):** Khách chốt phác đồ và tiến hành đặt cọc/thanh toán.- **Treatment Ongoing (Đang điều trị):** Rất quan trọng đối với các ca dài hạn như Niềng răng hay Implant để theo dõi tiến độ từng tháng.- **Completed (Hoàn tất):** Kết thúc lộ trình lâm sàng, chuyển sang giai đoạn bảo hành và tái khám định kỳ.- **Review Requested (Đã xin Review):** Đã kích hoạt kịch bản xin đánh giá 5 sao trên Google Maps hoặc quay video cảm nhận.- **Referral Potential (Khả năng giới thiệu cao):** Khách hàng cực kỳ hài lòng, sẵn sàng tham gia vào chương trình đại sứ thương hiệu để giới thiệu người thân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4349a0f3-3191-4676-9126-0e7e61fc3c14','b433552c-37cd-4e12-846c-10624326a7e5',56,'text','CRM không đơn thuần là một phần mềm lưu trữ Excel được nâng cấp. Nó là một kỷ luật vận hành. Khi bạn xây dựng được một hệ thống CRM minh bạch, bạn đang thiết lập một tấm lưới lọc hoàn hảo, đảm bảo không có bất kỳ một khách hàng hay một cơ hội doanh thu nào bị bỏ sót trong cỗ máy tăng trưởng của mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('65e9b003-0bf2-4bb5-97fd-6626b3c2723b','13-growth-engine','fc2734c0-f7dd-4c22-9360-6e48f1097d17',3,'SALES - Nghệ thuật tư vấn xóa tan ràn cản','sales-nghe-thuat-tu-van-xoa-tan-ran-can',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('464a4d3c-b086-4745-93eb-0cc233fc0e00','65e9b003-0bf2-4bb5-97fd-6626b3c2723b',57,'image',NULL,'book/13-growth-engine/0f489aa4-10b4-44e0-8e50-4cd21dc7b83c-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3342892-ef2c-4e9e-8390-e73b36ed01d6','65e9b003-0bf2-4bb5-97fd-6626b3c2723b',58,'text','Trong tư duy vận hành phòng khám RHM, một sai lầm chí mạng là coi đội ngũ Sales (Telesale/Tư vấn viên) giống như những người đi đi săn khách và chào mời sản phẩm. Thực tế, Sales trong nha khoa tuyệt đối không phải là "ép" khách hàng xuống tiền.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7737f118-5eb2-4320-bc36-ee5f1069587b','65e9b003-0bf2-4bb5-97fd-6626b3c2723b',59,'text','Sales là một nghệ thuật dẫn dắt tâm lý, giúp bệnh nhân đi qua một hành trình trọn vẹn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1af452bb-3bd0-419b-8d7b-5e393453a2c5','65e9b003-0bf2-4bb5-97fd-6626b3c2723b',60,'text','**Hiểu vấn đề → Tin giải pháp → Tin bác sĩ → Tin phòng khám → Quyết định điều trị.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('02532406-35e8-4c0a-b60b-3760ebf31793','65e9b003-0bf2-4bb5-97fd-6626b3c2723b',61,'text','Mục tiêu cao nhất là xóa bỏ sự e ngại, mang lại cho họ cảm giác an tâm tuyệt đối để họ thực sự thấy "thích làm răng", coi việc chăm sóc nụ cười là một trải nghiệm tích cực chứ không phải là một sự ép buộc đầy lo âu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('29fbe195-12f1-4983-91b7-0d16b3eaebde','13-growth-engine','65e9b003-0bf2-4bb5-97fd-6626b3c2723b',4,'Sales Phải Bắt Nguồn Từ Chuyên Môn: Trận Chiến Phá Vỡ Rào Cản','sales-phai-bat-nguon-tu-chuyen-mon-tran-chien-pha-vo-rao-can',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d84a09dc-7a6e-4530-9491-91e696284d4c','29fbe195-12f1-4983-91b7-0d16b3eaebde',62,'text','Trong nha khoa, chi phí cao và nỗi sợ can thiệp y tế khiến khách hàng luôn dựng lên những bức tường phòng thủ vững chắc. Để chốt được lịch hẹn, người tư vấn không thể chỉ dùng "văn mẫu", mà phải dùng kiến thức chuyên môn và sự thấu cảm để hóa giải từng rào cản một:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d2e7fb0-eb86-4c20-9e20-83ae93059a49','29fbe195-12f1-4983-91b7-0d16b3eaebde',63,'text','- **Sợ đau:** Thay vì hứa suông "làm nhanh lắm không đau đâu", hãy giải thích rõ ràng về quy trình, công nghệ máy móc hiện đại và hệ thống gây tê kỹ thuật số để tạo sự an tâm từ gốc rễ.- **Sợ giá cao:** Đừng vội mang các gói giảm giá ra chào mời. Hãy phân tích giá trị họ nhận được và hậu quả (chi phí sẽ còn khổng lồ hơn, thời gian điều trị kéo dài hơn) nếu tiếp tục trì hoãn.- **Sợ không hiệu quả:** Ngôn từ không bao giờ thuyết phục bằng hình ảnh. Hãy lập tức đưa ra những Case Study thực tế, những ca lâm sàng tương tự mà phòng khám đã xử lý thành công.- **Sợ bị "vẽ" bệnh, ép mua dịch vụ:** Sự trung thực là vũ khí tối thượng. Cần tư vấn đúng trọng tâm vấn đề, minh bạch trong từng bước của phác đồ.- **Cần hỏi ý kiến người thân:** Thay vì hối thúc, hãy cung cấp ngay một bộ tài liệu chuẩn chỉnh (video, hình ảnh, bài phân tích) để khách hàng dùng chính tài liệu đó làm "vũ khí" thuyết phục gia đình.- **So sánh với nhiều phòng khám khác:** Làm nổi bật sự khác biệt cốt lõi—không nằm ở việc ai rẻ hơn, mà nằm ở năng lực chuyên môn của bác sĩ, tính cá nhân hóa trong phác đồ và trải nghiệm dịch vụ vô trùng tuyệt đối.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d30c49f5-4253-40e1-a655-2ffc38726a41','13-growth-engine','65e9b003-0bf2-4bb5-97fd-6626b3c2723b',4,'Quy Trình Tư Vấn Chuẩn Mực: Đường Ống Kéo Khách Đến Ghế Răng','quy-trinh-tu-van-chuan-muc-uong-ong-keo-khach-en-ghe-rang',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0048006-8014-4e74-bb19-084b55228d64','d30c49f5-4253-40e1-a655-2ffc38726a41',64,'text','Một cuộc tư vấn xuất sắc không phụ thuộc vào cảm hứng hay tài ăn nói bẩm sinh của nhân viên, mà dựa trên một quy trình có tính kỷ luật cao. Đường ống lý tưởng phải đi qua các nấc thang:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9dbf61ca-02d9-4700-8fab-4f1614828753','d30c49f5-4253-40e1-a655-2ffc38726a41',65,'image',NULL,'book/13-growth-engine/c9029259-bbd4-483d-83be-04d3d8311ce2-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b5bde4d9-23de-4fbe-9a68-1e89db7a2276','13-growth-engine','65e9b003-0bf2-4bb5-97fd-6626b3c2723b',4,'Chuẩn Hóa Kịch Bản (Script): "Vũ Khí" Thực Chiến Cho Đội Ngũ','chuan-hoa-kich-ban-script-vu-khi-thuc-chien-cho-oi-ngu',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15355b0c-5c84-4265-a3ab-947d4ef99838','b5bde4d9-23de-4fbe-9a68-1e89db7a2276',66,'text','Để quy trình trên vận hành trơn tru và nhất quán trên toàn hệ thống, phòng khám cần trang bị một bộ kịch bản chi tiết cho từng giai đoạn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aa6598ec-3ef8-4c25-aa87-6e72749301ec','b5bde4d9-23de-4fbe-9a68-1e89db7a2276',67,'text','- **Mở đầu:** Chào hỏi chuyên nghiệp, ấm áp và ngay lập tức xác nhận nhu cầu cốt lõi để khách thấy họ đang nói chuyện đúng người.- **Khai thác:** Biến mình thành một chuyên gia tâm lý—Hỏi sâu về tình trạng, thời gian bị đau, mức độ ảnh hưởng đến sinh hoạt và mong muốn thực sự của họ.- **Tư vấn:** Đóng vai trò là người "phiên dịch" các thuật ngữ y khoa phức tạp thành ngôn ngữ đời thường, nhẹ nhàng và dễ hiểu.- **Tạo niềm tin:** Tung "vũ khí" đúng thời điểm (gửi link Case tương tự, Review của khách cũ, Profile uy tín của bác sĩ trực tiếp điều trị).- **Chốt lịch:** Tuyệt đối tránh các câu hỏi đóng như *"Anh/chị có muốn qua khám không?"*. Hãy dùng câu hỏi định hướng sự lựa chọn: *"Bác sĩ đang trống lịch vào 9h sáng thứ Ba và 3h chiều thứ Tư, anh/chị sắp xếp được khung giờ nào cho tiện nhất ạ?"*- **Xử lý từ chối:** Chuẩn bị sẵn các phương án phản hồi sắc bén cho những tình huống từ chối kinh điển (chê đắt, bận rộn, sợ đau, cần suy nghĩ thêm).- **Nhắc lịch & Follow-up:** Xác nhận lại trước ngày khám. Nếu khách hàng "bùng" lịch hoặc chưa chốt phác đồ sau khi khám, phải có kịch bản gọi lại ngay để tìm hiểu nguyên nhân gốc rễ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4476be31-e2da-46bd-b9cb-e6737099bd49','13-growth-engine','65e9b003-0bf2-4bb5-97fd-6626b3c2723b',4,'Quản Trị Bằng Số Liệu: Bộ KPI Của Khối Sales','quan-tri-bang-so-lieu-bo-kpi-cua-khoi-sales',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('477e8209-c965-44bd-9b90-b25f55682a43','4476be31-e2da-46bd-b9cb-e6737099bd49',68,'image',NULL,'book/13-growth-engine/a734dfec-324b-4c58-87f3-42e7a7e23220-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cbe06755-bdae-4f99-b916-eca4812e42a3','4476be31-e2da-46bd-b9cb-e6737099bd49',69,'text','Giống như việc đo lường quảng cáo, hiệu suất của đội ngũ Sales cũng phải được số hóa hoàn toàn. Nếu không có những chỉ số này, bạn sẽ mù mờ về sức khỏe của cỗ máy tăng trưởng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7584b0c-5ffb-4ba3-9385-9f510efb2154','4476be31-e2da-46bd-b9cb-e6737099bd49',70,'text','- **Response Time (Thời gian phản hồi):** Tốc độ liên hệ lại với Lead từ khi đổ về CRM (Chỉ số này càng nhỏ, tỷ lệ khách nhấc máy càng cao).- **Contact Rate (Tỷ lệ liên hệ được):** Bao nhiêu phần trăm lượng Lead thực sự nghe máy hoặc trả lời tin nhắn.- **Booking Rate (Tỷ lệ đặt lịch):** Thước đo phản ánh kỹ năng khơi gợi nhu cầu và xử lý rào cản của Telesale.- **Show-up Rate (Tỷ lệ khách đến khám):** Thước đo sức nặng của lời hứa và hiệu quả của hệ thống nhắc lịch tự động.- **Consultation-to-Treatment Rate (Tỷ lệ từ khám sang điều trị):** Tại điểm chạm này, trách nhiệm chốt phác đồ thuộc về Bác sĩ trực tiếp tư vấn lâm sàng.- **Closing Rate (Tỷ lệ chốt dịch vụ):** Tổng tỷ lệ chuyển đổi cuối cùng của toàn bộ phễu.- **Average Treatment Value (Giá trị trung bình mỗi ca):** Đo lường khả năng up-sale/cross-sale (bán chéo) hợp lý dựa trên đúng nhu cầu y khoa.- **Lost Reason (Lý do mất khách):** Chỉ số mang tính bài học. Phải ghi nhận cực kỳ chi tiết (do chê giá, do đi xa, hay do thái độ) để liên tục tối ưu lại kịch bản, sản phẩm và dịch vụ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fdb09775-6108-4d83-be22-3f66b2f83841','4476be31-e2da-46bd-b9cb-e6737099bd49',71,'text','Khi bạn ráp nối thành công một đội ngũ Sales thiện chiến, có quy trình bài bản vào một hệ thống CRM chuẩn mực, bạn đã nắm trong tay một nửa sức mạnh của Growth Engine, sẵn sàng biến mọi chi phí Marketing thành những con số lợi nhuận vững chắc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8592f62a-2360-42a2-9251-a008d7c3ce88','13-growth-engine','fc2734c0-f7dd-4c22-9360-6e48f1097d17',3,'AUTOMATION - Hệ thống tự động hóa','automation-he-thong-tu-ong-hoa',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('941e6389-626e-454e-b6a5-46068f6e0ef5','8592f62a-2360-42a2-9251-a008d7c3ce88',72,'text','Sau khi đã xây dựng được kho Content sắc bén, một hệ thống Ads tăng tốc mượt mà, một bộ nhớ CRM minh bạch và một đội ngũ Sales thiện chiến, bài toán tiếp theo mà các phòng khám RHM phải đối mặt là: **Sức người có hạn.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cfa83318-93f2-4b96-9aeb-16f0b7327053','8592f62a-2360-42a2-9251-a008d7c3ce88',73,'text','Lễ tân có thể quên gọi nhắc lịch hẹn lúc đông khách. Tư vấn viên có thể sót việc gửi tin nhắn hỏi thăm bệnh nhân sau khi nhổ răng khôn. Quản lý có thể mệt mỏi khi mỗi ngày phải hì hục gom file Excel để làm báo cáo. Đó là lúc chúng ta cần đến mảnh ghép cuối cùng của Growth Engine: **Automation (Tự động hóa).**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9ee75af-32cf-4b82-b960-4d37ff14d29d','8592f62a-2360-42a2-9251-a008d7c3ce88',74,'text','Nhiều người e ngại rằng tự động hóa sẽ làm mất đi sự kết nối giữa người với người trong ngành y tế. Sự thật thì hoàn toàn ngược lại. Automation không sinh ra để thay thế con người; nó sinh ra để gánh vác những thao tác thủ công lặp đi lặp lại, từ đó giải phóng thời gian để đội ngũ của bạn tập trung vào việc quan trọng nhất: **Giao tiếp, thấu cảm và chăm sóc bệnh nhân.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e7e02167-5b9e-4e0d-8be1-70a227423c44','13-growth-engine','8592f62a-2360-42a2-9251-a008d7c3ce88',4,'Sức Mạnh Của Tự Động Hóa: Vì Sao Không Thể Thiếu?','suc-manh-cua-tu-ong-hoa-vi-sao-khong-the-thieu',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e657676c-8166-4e4f-854e-20423ae03fba','e7e02167-5b9e-4e0d-8be1-70a227423c44',75,'text','Khi bạn thiết lập được một hệ thống Automation chuẩn mực, bạn đang trao cho phòng khám những lợi thế sinh tử:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5da927b4-9181-4038-9d9b-fe59a25f53d9','e7e02167-5b9e-4e0d-8be1-70a227423c44',76,'text','- **Tốc độ phản hồi (Speed to lead):** Khách hàng không bao giờ bị bỏ quên. Một tin nhắn xác nhận được gửi đi ngay giây phút họ để lại thông tin sẽ giữ chân họ ở lại với bạn thay vì tìm sang đối thủ.- **Kỷ luật Follow-up:** Máy móc không biết quên. Các lịch hẹn gọi lại sẽ được nhắc nhở đều đặn, đẩy tỷ lệ khách hàng quay lại phễu tư vấn lên mức cao nhất.- **Giảm thiểu tỷ lệ "Bùng" lịch (No-show):** Những tin nhắn/Zalo nhắc lịch tự động trước 24h và 2h không chỉ thể hiện sự chuyên nghiệp mà còn cứu vãn hàng chục ca trống ghế mỗi tháng.- **Chăm sóc sau điều trị tinh tế:** Tự động gửi hướng dẫn chườm đá, uống thuốc sau tiểu phẫu, giúp bệnh nhân an tâm và nâng cao điểm chạm hài lòng.- **Gia tăng "Tài sản Niềm tin" (Trust Assets):** Xin đánh giá (Review) đúng vào thời điểm khách hàng đang hài lòng nhất một cách tự động, giúp phòng khám liên tục tích lũy uy tín.- **Kiểm soát thời gian thực:** Founder/Quản lý không cần chờ đến cuối tháng mới biết phòng khám đang lỗ hay lãi nhờ các báo cáo tự động cập nhật mỗi ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('48243ad3-cc6a-449f-a9d0-903ef001f768','13-growth-engine','8592f62a-2360-42a2-9251-a008d7c3ce88',4,'Các Mắt Xích Automation Trọng Yếu Cần Triển Khai','cac-mat-xich-automation-trong-yeu-can-trien-khai',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7b0bef90-e34f-48a6-8b10-de7c93125f35','48243ad3-cc6a-449f-a9d0-903ef001f768',77,'text','Để cỗ máy vận hành trơn tru, đây là những kịch bản tự động hóa bắt buộc phải có trong hệ thống CRM của bạn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a23c77ba-cb5a-4b8e-a7b4-dcf1dd4401c6','48243ad3-cc6a-449f-a9d0-903ef001f768',78,'text','- **Lead Capture (Bắt Lead tự động):** Tự động gom toàn bộ thông tin khách hàng từ Form Website, Inbox Facebook, hay quảng cáo đổ về một màn hình CRM duy nhất.- **Auto Tagging (Gắn nhãn thông minh):** Hệ thống tự đọc dữ liệu và gắn thẻ phân loại (Ví dụ: Khách quan tâm Implant, Nguồn từ TikTok, Khách Nóng).- **Auto Assignment (Chia số công bằng):** Dựa trên luật chia (Round-robin) hoặc năng lực, hệ thống tự động phân bổ Lead cho đúng Telesale/Tư vấn viên phụ trách để xử lý ngay.- **Follow-up Reminder (Nhắc việc Telesale):** Tự động báo chuông cho nhân viên khi đến ngày/giờ cần gọi lại cho khách hàng đang cân nhắc.- **Appointment Reminder (Nhắc lịch hẹn):** Gửi SMS/Zalo thông báo lịch khám, tên bác sĩ và địa chỉ phòng khám cho bệnh nhân.- **No-show Recovery (Kéo lại khách bỏ hẹn):** Kích hoạt chuỗi tin nhắn hỏi thăm nhẹ nhàng nếu khách không đến, kèm theo lời mời chọn lại khung giờ khác.- **Post-treatment Care (Chăm sóc hậu phẫu/sau điều trị):** Tự động hóa việc gửi dặn dò y khoa (cách vệ sinh răng niềng, lưu ý sau khi cấy trụ Implant...).- **Review Request (Xin đánh giá):** Hệ thống tự động gửi link Google Maps hoặc Fanpage để xin đánh giá ngay sau khi trạng thái hồ sơ chuyển sang "Hoàn tất điều trị".- **Referral Prompt (Gợi ý lan tỏa):** Gửi các mã ưu đãi cho người thân đối với những bệnh nhân đã chấm điểm hài lòng cao.- **Report Automation (Báo cáo tự động):** Tự động xuất dashboard tổng hợp KPI (số Lead, chi phí Ads, tỷ lệ chốt, doanh thu) hằng ngày/tuần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c2cb5a0e-6c93-4191-a6d6-06d0bb7ded07','13-growth-engine','8592f62a-2360-42a2-9251-a008d7c3ce88',4,'Luồng Chảy Tiêu Chuẩn Của Hệ Thống Tự Động (Master Flow)','luong-chay-tieu-chuan-cua-he-thong-tu-ong-master-flow',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('90543175-0bc5-46d5-aac8-044a9cb45c6f','c2cb5a0e-6c93-4191-a6d6-06d0bb7ded07',79,'text','Hãy hình dung hành trình của một khách hàng đi xuyên qua cỗ máy Growth Engine hoàn chỉnh của bạn, mọi thứ diễn ra nhịp nhàng như một bản nhạc:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6aea3d81-a4c4-443e-81ba-37db54eeb859','c2cb5a0e-6c93-4191-a6d6-06d0bb7ded07',80,'image',NULL,'book/13-growth-engine/c41cea38-8c36-4fc4-a585-0bb0d83cec1c-img11.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a6432ee6-dd43-4229-8715-93690b5800e8','c2cb5a0e-6c93-4191-a6d6-06d0bb7ded07',81,'text','Growth Engine không phải là một công cụ thần thánh mua về cài đặt là xong. Nó là **một triết lý vận hành**. Khi Content khơi gợi đúng nhu cầu, Ads tiếp cận đúng người, CRM lưu trữ không sót một dữ liệu nào, đội ngũ Sales tư vấn bằng cái tâm chuyên môn, và Automation lo liệu mọi thao tác hậu cần bền bỉ phía sau. Lúc đó, phòng khám RHM của bạn đã chính thức thoát khỏi sự phụ thuộc vào sự may rủi, để bước vào kỷ nguyên của sự tăng trưởng chủ động, bền vững và có thể dự báo trước.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3dca8517-9d10-49e3-8bdb-361d94e87fdd','13-growth-engine',NULL,2,'13.3 GROWTH ENGINE - Trái tim của hệ sinh thái phát triển nha khoa thực chiến','133-growth-engine-trai-tim-cua-he-sinh-thai-phat-trien-nha-khoa-thuc-chien',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48b72c0b-99e3-4797-bbf9-d35a439624b1','3dca8517-9d10-49e3-8bdb-361d94e87fdd',82,'text','Trải qua việc bóc tách từng mảnh ghép, chúng ta đi đến một sự thật cốt lõi: Growth Engine không đơn thuần là một khái niệm, nó là phần tinh túy nhất để biến toàn bộ hệ sinh thái Dental Empire thành doanh thu thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b18c3438-0c7f-4f8a-85c2-6c6e011f8f9a','3dca8517-9d10-49e3-8bdb-361d94e87fdd',83,'text','Nó đóng vai trò là một bộ não trung tâm, đan chéo và kết nối hoàn hảo **6 nguồn sức mạn**h của doanh nghiệp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0b3821dc-17e7-4674-851f-f2353bdd577e','3dca8517-9d10-49e3-8bdb-361d94e87fdd',84,'text','- **Content (Nội dung) - Tạo ra niềm tin:** Thay đổi nhận thức, xóa bỏ rào cản sợ hãi để bệnh nhân thấu hiểu và thực sự "thích làm răng".- **Ads (Quảng cáo) - Tạo ra tốc độ:** Khuếch đại thông điệp, bứt phá giới hạn tiếp cận thị trường và rút ngắn hành trình ra quyết định.- **CRM (Quản trị quan hệ) - Giữ trọn dữ liệu:** Đảm bảo không một khách hàng hay một cơ hội kinh doanh nào bị đánh rơi giữa chừng.- **Sales (Tư vấn lâm sàng) - Tạo ra chuyển đổi:** Nghệ thuật hóa giải sự từ chối bằng lòng thấu cảm và chuyên môn y khoa sắc bén.- **Clinic System & Data (Lâm sàng & Dữ liệu) - Tạo ra sự tối ưu:** Nơi lời hứa thương hiệu được kiểm chứng bằng trải nghiệm thực tế trên ghế nha, sinh ra dữ liệu chuẩn xác để liên tục cải tiến.- **Automation (Tự động hóa) - Tạo ra quy mô:** Những bánh răng chạy ngầm không mệt mỏi, giải phóng sức lao động thủ công và giữ nhịp độ chăm sóc hoàn hảo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('80985b50-0ac8-4084-a9c4-9a0e46f23ac8','3dca8517-9d10-49e3-8bdb-361d94e87fdd',85,'text','Một khi 6 bánh răng này được tinh chỉnh và khớp nối đồng bộ vào nhau, bức tranh kinh doanh của bạn sẽ hoàn toàn thay đổi. Sự tăng trưởng của phòng khám không còn là những cú "ăn may" ngẫu nhiên hay phụ thuộc vào sự phập phù của cảm xúc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e51bbf5c-9a32-42a8-9d4d-0350a2f930d1','3dca8517-9d10-49e3-8bdb-361d94e87fdd',86,'image',NULL,'book/13-growth-engine/c65b6ac4-9078-4128-ad97-dd65e52b18ce-img12.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7e55fa2c-c5ca-4551-8aaa-fe97d093ebd5','3dca8517-9d10-49e3-8bdb-361d94e87fdd',87,'text','Thay vào đó, bạn chính thức làm chủ một cỗ máy tăng trưởng khoa học: **Có thể đo lường từng đồng chi phí, có thể lặp lại những chu kỳ thành công, và hoàn toàn có thể nhân bản, mở rộng quy mô một cách bền vững.** Đó chính là đích đến cuối cùng của một nhà quản trị nha khoa xuất sắc!',NULL,NULL,NULL,NULL,NULL);
